#include <bits/stdc++.h>
using namespace std;

const int N=2e7+10;

int n,m,z[N],p[N];
char s[N],t[N];

int main(){
    scanf("%s%s",t+1,s+1);
    n=strlen(s+1),m=strlen(t+1);
    s[n+1]='#',t[m+1]='$';
    z[1]=n;
    int l,r=0;
    for(int i=2;i<=n;i++){
        if(r<i) z[i]=0;
        else z[i]=min(r-i+1,z[i-l+1]);
        while(s[i+z[i]]==s[z[i]+1]) z[i]++;
        if(i+z[i]-1>r) l=i,r=i+z[i]-1;
    }
    while(s[p[1]+1]==t[p[1]+1]) p[1]++;
    r=0;
    for(int i=2;i<=m;i++){
        if(r<i) p[i]=0;
        else p[i]=min(r-i+1,z[i-l+1]);
        while(t[i+p[i]]==s[p[i]+1]) p[i]++;
        if(i+p[i]-1>r) l=i,r=i+p[i]-1;
    }
    long long az=0,ap=0;
    for(int i=1;i<=n;i++)
        az^=1ll*i*(z[i]+1);
    for(int i=1;i<=m;i++)
        ap^=1ll*i*(p[i]+1);
    printf("%lld\n%lld\n",az,ap);
    return 0;
}
